import{_ as a,c as n,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"Advanced: Deep Dive | opencode-supermemory","description":"Master Supermemory's compaction mechanism and configuration options. Deeply understand context management, optimize plugin performance, and adapt to project requirements.","frontmatter":{"title":"Advanced: Deep Dive | opencode-supermemory","sidebarTitle":"Advanced","subtitle":"Advanced: Deep Dive","description":"Master Supermemory's compaction mechanism and configuration options. Deeply understand context management, optimize plugin performance, and adapt to project requirements.","order":3},"headers":[],"relativePath":"ru/supermemoryai/opencode-supermemory/advanced/index.md","filePath":"ru/supermemoryai/opencode-supermemory/advanced/index.md"}`),t={name:"ru/supermemoryai/opencode-supermemory/advanced/index.md"};function s(i,e,p,c,d,l){return r(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="расширенные-функции" tabindex="-1">Расширенные функции <a class="header-anchor" href="#расширенные-функции" aria-label="Permalink to &quot;Расширенные функции&quot;">​</a></h1><p>Эта глава глубоко объясняет низкоуровневые механизмы и расширенные параметры конфигурации Supermemory. Вы научитесь оптимизировать производительность движка памяти и настраивать поведение плагина в соответствии с требованиями проекта.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><div class="grid-cards"><h3 id="принцип-упреждающего-сжатия" tabindex="-1"><a href="./compaction/">Принцип упреждающего сжатия</a> <a class="header-anchor" href="#принцип-упреждающего-сжатия" aria-label="Permalink to &quot;[Принцип упреждающего сжатия](./compaction/)&quot;">​</a></h3><p>Глубокое понимание механизма автоматического сжатия, триггерного по порогу токенов. Узнайте, как Supermemory перед переполнением контекста активно генерирует структурированную сводку и сохраняет ее постоянно, предотвращая проблему &quot;потери памяти&quot; в длительных сессиях.</p><h3 id="подробная-настроика" tabindex="-1"><a href="./configuration/">Подробная настройка</a> <a class="header-anchor" href="#подробная-настроика" aria-label="Permalink to &quot;[Подробная настройка](./configuration/)&quot;">​</a></h3><p>Настройте порог сжатия, правила триггеризации по ключевым словам и параметры поиска. Овладей всеми опциями файла конфигурации, чтобы Supermemory идеально соответствовал вашему рабочему процессу.</p></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Шаг 1              Шаг 2                                    │</span></span>
<span class="line"><span>│  Принцип упреждающего   →   Подробная настройка              │</span></span>
<span class="line"><span>│  сжатия              (Понимание механизма)      (Настройка) │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Рекомендуемый порядок</strong>:</p><ol><li><strong>Сначала изучите принцип сжатия</strong>: Поймите, как Supermemory автоматически управляет контекстом — это основа расширенной настройки.</li><li><strong>Затем изучите подробную настройку</strong>: Только после понимания механизма вы сможете принимать обоснованные решения о конфигурации (например, какой порог подходит).</li></ol><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Подтверждение перед началом</p><p>Содержание этой главы предполагает, что вы завершили следующее обучение:</p><ul><li>✅ <a href="./../start/getting-started/">Быстрый старт</a>: Плагин установлен и API Key настроен</li><li>✅ <a href="./../core/memory-management/">Область действия памяти и жизненный цикл</a>: Понимание различий между User Scope и Project Scope</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы рекомендуется продолжить изучение:</p><ul><li><strong><a href="./../security/privacy/">Конфиденциальность и безопасность данных</a></strong>: Узнайте о механизме автоматического удаления чувствительных данных, чтобы убедиться, что ваш код и ключи не будут случайно загружены.</li></ul>`,13)])])}const h=a(t,[["render",s]]);export{u as __pageData,h as default};
